"""Сервис загрузки списка моделей из провайдеров и добавления новых записей в реестр.Логирование сырых ответов API — только в базовом классе провайдера при запросах."""from __future__ import annotationsfrom dataclasses import dataclass, fieldfrom .llm_model_manager import LLMModelManagerfrom src.modules.llm_providers.providers.llm_provider import LLMProviderfrom src.modules.llm_providers.schemas.models import LLMModelsRequest@dataclassclass SyncModelsResult:    """Результат синхронизации реестра с провайдерами."""    providers_count: int = 0    models_total: int = 0    models_new: int = 0    errors: list[str] = field(default_factory=list)class SyncModelRegistryService:    """    Статичный сервис синхронизации реестра моделей.    Путь к реестру задаётся в boot.    Получает список провайдеров из LLMProvider (config из хранилища модуля), для каждого — список моделей.    Модели, которых ещё нет в реестре, добавляются с полями по умолчанию:    can_update=True, enabled=True, created.    """    @staticmethod    def sync_models() -> SyncModelsResult:        """        Для каждого доступного провайдера запрашивает список моделей;        модели, которых нет в реестре, добавляет с can_update=True, enabled=True, created.        Возвращает результат: число провайдеров, всего моделей, добавлено новых.        """        registry = LLMProvider()        manager = LLMModelManager()        to_add: list[dict] = []        providers_count = 0        models_total = 0        errors: list[str] = []        for provider_code in registry.provider_codes():            try:                response = registry.models(LLMModelsRequest(provider=provider_code))            except Exception as e:                errors.append(f"{provider_code}: {e}")                continue            providers_count += 1            for model_info in response.models:                models_total += 1                model_key = f"{model_info.provider}@{model_info.model}"                if manager.exists(model_key):                    continue                record = manager.create_empty(model_key, created=model_info.created)                to_add.append(record)        models_new = manager.add_models(to_add)        return SyncModelsResult(            providers_count=providers_count,            models_total=models_total,            models_new=models_new,            errors=errors,        )